from datetime import datetime, timedelta
from decimal import Decimal

def calculate_sla_credit(
    customer_tier: str,
    incident_duration: timedelta,
    monthly_fee: Decimal,
) -> dict:
    # SLA commitments by tier
    SLA_UPTIME = {
        "tier1": Decimal("99.99"),  # 4.38 min/month allowance
        "tier2": Decimal("99.9"),   # 43.8 min/month allowance
        "tier3": Decimal("99.5"),   # 3.65 h/month allowance
    }
    CREDIT_SCHEDULE = {
        # (downtime_hours_threshold, credit_pct)
        "tier1": [(1, Decimal("10")), (4, Decimal("25")), (8, Decimal("50"))],
        "tier2": [(2, Decimal("10")), (8, Decimal("25")), (24, Decimal("50"))],
        "tier3": [(4, Decimal("10")), (24, Decimal("25"))],
    }
    duration_hours = Decimal(str(incident_duration.total_seconds() / 3600))
    credit_pct = Decimal("0")
    for threshold, pct in CREDIT_SCHEDULE.get(customer_tier, []):
        if duration_hours >= threshold:
            credit_pct = pct
    credit_amount = (monthly_fee * credit_pct / 100).quantize(Decimal("0.01"))
    return {
        "duration_hours": float(duration_hours),
        "sla_uptime_pct": str(SLA_UPTIME.get(customer_tier, "N/A")),
        "credit_percentage": float(credit_pct),
        "credit_amount": float(credit_amount),
        "requires_credit": credit_pct > 0,
    }

from dataclasses import dataclass, field
from datetime import datetime

@dataclass
class IncidentReportTracker:
    incident_id: str
    resolved_at: datetime
    severity: str
    # step completion timestamps
    root_cause_confirmed_at: datetime | None = None
    ic_review_completed_at: datetime | None = None
    legal_review_completed_at: datetime | None = None   # required for P0 privacy
    published_at: datetime | None = None
    requires_legal_review: bool = False

    def deadline(self) -> datetime:
        from datetime import timedelta
        return self.resolved_at + timedelta(days=5)

    def days_remaining(self) -> float:
        from datetime import timezone
        now = datetime.now(tz=self.resolved_at.tzinfo)
        return (self.deadline() - now).total_seconds() / 86400

    def blocking_steps(self) -> list[str]:
        steps = []
        if not self.root_cause_confirmed_at:
            steps.append("Root cause not confirmed")
        if not self.ic_review_completed_at:
            steps.append("IC review pending")
        if self.requires_legal_review and not self.legal_review_completed_at:
            steps.append("Legal review pending")
        return steps

    def can_publish(self) -> bool:
        return len(self.blocking_steps()) == 0

def schedule_csat_survey(incident_id: str, resolved_at: datetime) -> dict:
    from datetime import timedelta
    survey_send_at = resolved_at + timedelta(days=7)
    return {
        "incident_id": incident_id,
        "survey_send_at": survey_send_at.isoformat(),
        "template": "incident_csat_v2",
        "question": "How satisfied were you with Anthropic's communication during the incident?",
        "scale": "1-5",
        "free_text": True,
        "audience": "affected_customers_p0",
    }

def aggregate_csat_results(responses: list[dict]) -> dict:
    scores = [r["score"] for r in responses if "score" in r]
    if not scores:
        return {"count": 0, "mean": None, "low_score_pct": None}
    mean = sum(scores) / len(scores)
    low = sum(1 for s in scores if s <= 2) / len(scores) * 100
    return {
        "count": len(scores),
        "mean": round(mean, 2),
        "low_score_pct": round(low, 1),
        "needs_review": mean < 3.5 or low > 20,
    }
